// Helper to extract JSON groups
const getTireGroups = (client: Client): TireGroup[] => {
    let groups: TireGroup[] = [];
    if (client.metadata) {
        try {
            const parsed = JSON.parse(client.metadata);
            if (parsed.groups && Array.isArray(parsed.groups)) {
                groups = parsed.groups;
            }
        } catch(e) {}
    }
    if (groups.length === 0 && client['Заказ - QR']) {
        const jsonMatch = client['Заказ - QR'].match(/\|\|JSON:(.*)$/);
        if (jsonMatch) {
            try {
                const parsed = JSON.parse(jsonMatch[1]);
                if (parsed.groups && Array.isArray(parsed.groups)) {
                    groups = parsed.groups;
                }
            } catch (e) {}
        }
    }
    return groups;
}

const TireGroupsView: React.FC<{ client: Client }> = ({ client }) => {
    const groups = getTireGroups(client);

    if (groups.length === 0) return null;

    return (
         <div className="col-span-2 space-y-2 mt-2 border-t border-gray-100 dark:border-gray-700 pt-2">
            <p className="text-xs font-bold text-gray-500 uppercase">Состав комплекта:</p>
            {groups.map((g: TireGroup, idx: number) => (
                <div key={idx} className="flex justify-between items-center text-sm bg-gray-50 dark:bg-gray-900/40 p-2 rounded">
                     <span>
                         <span className="font-bold">{g.count} шт</span> • {g.brand} {g.model}
                     </span>
                     <span className="font-mono text-gray-600 dark:text-gray-400">
                         {g.width}/{g.profile} R{g.diameter}
                     </span>
                </div>
            ))}
         </div>
    );
};

const ClientDetailModal: React.FC<{
  isOpen: boolean;
  onClose: () => void;
  client: Client;
  headers: string[];
  templates: MessageTemplate[];
  onSave: (clientData: Partial<Client>) => Promise<void>;
  onDelete: (clientId: string) => Promise<void>;
  onSendMessage: (client: Client, templateContent: string) => Promise<void>;
  refreshData: () => Promise<void>;
  showToast: (message: string, type: 'success' | 'error') => void;
}> = ({ isOpen, onClose, client, headers, templates, onSave, onDelete, onSendMessage, refreshData, showToast }) => {

    const navigate = useNavigate();
    const [activeTab, setActiveTab] = useState<'details' | 'history' | 'photos'>('details');
    const [mode, setMode] = useState<'view' | 'edit' | 'message'>('view');
    const [formData, setFormData] = useState<Partial<Client>>(client);
    const [selectedTemplateName, setSelectedTemplateName] = useState<string>('');
    const [preview, setPreview] = useState('');
    const [isSubmitting, setIsSubmitting] = useState(false);

    useEffect(() => {
        setFormData(client);
        setActiveTab('details');
        setMode('view');
    }, [client]);

    useEffect(() => {
        if (mode === 'message' && templates.length > 0 && !selectedTemplateName && preview === '') {
            setSelectedTemplateName(templates[0]?.['Название шаблона'] || '');
        }
    }, [templates, selectedTemplateName, mode, preview]);

    useEffect(() => {
        // Only update preview from template if we have a template selected AND we are not in custom mode (where template name is empty)
        if (selectedTemplateName && formData) {
            const selectedTemplate = templates.find(t => t['Название шаблона'] === selectedTemplateName);
            if (selectedTemplate) {
                let content = selectedTemplate['Содержимое (HTML)'];
                Object.keys(formData).forEach(key => {
                    content = content.replace(new RegExp(`{{${key}}}`, 'g'), String(formData[key as keyof Client] || ''));
                });
                setPreview(content);
            }
        }
    }, [selectedTemplateName, templates, formData]);

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
        const { name, value, type } = e.target;
        const isNumber = type === 'number';
        setFormData(prev => prev ? ({ ...prev, [name]: isNumber ? parseFloat(value) || 0 : value }) : null);
    };

    const handleSave = async () => {
        if (!formData) return;
        setIsSubmitting(true);
        await onSave(formData);
        setIsSubmitting(false);
        setMode('view');
    };

    const handleDelete = async () => {
        if (window.confirm(`Вы уверены, что хотите удалить клиента "${client['Имя клиента']}"?`)) {
            setIsSubmitting(true);
            await onDelete(client.id);
            setIsSubmitting(false);
        }
    };

    const handleSendMessage = async () => {
        if (preview) {
            setIsSubmitting(true);
            await onSendMessage(client, preview);
            setIsSubmitting(false);
            setMode('view');
        }
    };

    const handleNewOrder = () => {
        navigate('/add-client', { state: { clientToReorder: client } });
        onClose();
    };

    const handleGenerateReceipt = () => {
        const groups = getTireGroups(client);
        const formatCurrency = (val: number | undefined) => new Intl.NumberFormat('ru-RU', { style: 'currency', currency: 'RUB', minimumFractionDigits: 0 }).format(val || 0);

        let tiresText = '';
        if (groups.length > 0) {
            tiresText = groups.map((g, i) => `<b>📦 Комплект ${i + 1}:</b>
${g.count}шт • ${g.brand} ${g.model}
Размер: <b>${g.width}/${g.profile} R${g.diameter}</b>
Сезон: ${g.season} | Диски: ${g.hasRims}${g.dot ? `\nDOT: <b>${g.dot}</b>` : ''}`).join('\n\n');
        } else {
            tiresText = (client['Заказ - QR'] || '').split('||JSON:')[0];
        }

        const receiptHtml = `
<b>📃 ДЕТАЛИ ЗАКАЗА (ДОГОВОР)</b>

👤 <b>Клиент:</b> ${client['Имя клиента']}
🚗 <b>Авто:</b> ${client['Номер Авто']}
📞 <b>Телефон:</b> ${client['Телефон']}

🔢 <b>Договор №:</b> <code>${client['Договор']}</code>
📅 <b>Срок хранения:</b> ${client['Срок']} мес.
(с ${formatDateForDisplay(client['Начало'])} по ${formatDateForDisplay(client['Окончание'])})

- - - - - - - - - - - - - -
${tiresText}
- - - - - - - - - - - - - -

💰 <b>Сумма заказа:</b> ${formatCurrency(client['Общая сумма'])}
(Тариф: ${formatCurrency(client['Цена за месяц'])}/мес)
${Number(client['Долг']) > 0 ? `❗️ <b>К оплате (Долг):</b> ${formatCurrency(client['Долг'])}` : ''}

📍 <b>Склад:</b> ${client['Склад хранения']}

<i>Приём и хранение осуществляется на условиях публичной оферты otelshin.ru/dogovor</i>
`.trim().replace(/\n/g, '<br/>');

        setPreview(receiptHtml);
        setSelectedTemplateName(''); // Clear template selection so it doesn't overwrite
        setMode('message');
    };


    const renderContent = () => {
        if (!formData) return null;

        if (mode === 'edit') {
            return (
                 <form onSubmit={(e) => { e.preventDefault(); handleSave(); }} className="space-y-4 max-h-[60vh] overflow-y-auto p-1">
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                        {headers.filter(h => h !== 'id' && h !== 'photoUrls' && h !== 'metadata').map(header => (
                            <Input
                                key={header}
                                label={header}
                                name={header}
                                value={formData[header as keyof Client] || ''}
                                type={getFieldType(header)}
                                onChange={handleChange}
                                required={header === 'Имя клиента'}
                            />
                        ))}
                    </div>
                </form>
            );
        }

        if (mode === 'message') {
             return (
                <div className="space-y-4">
                    <div>
                        <label htmlFor="template" className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1.5">Шаблон</label>
                        <select 
                            id="template" 
                            value={selectedTemplateName} 
                            onChange={e => setSelectedTemplateName(e.target.value)} 
                            className="block w-full rounded-md border-gray-300 shadow-sm focus:border-primary-500 focus:ring-primary-500 py-2.5 px-3 dark:bg-gray-800 dark:border-gray-600 dark:text-white transition duration-150"
                        >
                            <option value="">-- Индивидуальное сообщение / Чек --</option>
                            {templates.map(t => <option key={t['Название шаблона']} value={t['Название шаблона']}>{t['Название шаблона']}</option>)}
                        </select>
                    </div>
                    <div>
                        <h4 className="text-md font-medium text-gray-800 dark:text-gray-200 mb-2">Сообщение (HTML)</h4>
                        <div 
                            className="p-3 border rounded-md bg-gray-50 dark:bg-gray-700/50 dark:border-gray-600 min-h-[150px] max-h-[30vh] overflow-y-auto font-mono text-sm whitespace-pre-wrap outline-none focus:ring-2 focus:ring-primary-500" 
                            contentEditable
                            onInput={(e) => setPreview(e.currentTarget.innerText)} // Allow editing manual text
                            dangerouslySetInnerHTML={{ __html: preview }}
                        />
                        <p className="text-xs text-gray-500 mt-1">Вы можете редактировать текст выше перед отправкой.</p>
                    </div>
                </div>
            )
        }

        const descClean = (formData['Заказ - QR'] || '').split('||JSON:')[0];

        return (
            <div className="space-y-4 max-h-[60vh] overflow-y-auto p-1">
                {activeTab === 'details' && (
                    <div className="space-y-4">
                         {/* Status Header */}
                        <div className="flex justify-end pb-2">
                             <span className={`px-3 py-1 rounded-full text-xs font-bold uppercase tracking-wide ${
                                 formData['Статус сделки'] === 'На складе' ? 'bg-green-100 text-green-800' : 
                                 formData['Статус сделки'] === 'Завершено' ? 'bg-gray-100 text-gray-800' : 'bg-yellow-100 text-yellow-800'
                             }`}>
                                 {formData['Статус сделки']}
                             </span>
                        </div>

                        {/* Top Metrics Grid (2x2) */}
                         <div className="grid grid-cols-2 gap-3">
                             {/* Card 1: Debt */}
                             <div className={`p-3 rounded-lg border ${Number(formData['Долг'] || 0) > 0 ? 'bg-red-50 border-red-100 dark:bg-red-900/10 dark:border-red-800' : 'bg-green-50 border-green-100 dark:bg-green-900/10 dark:border-green-800'}`}>
                                <p className={`text-xs font-bold uppercase ${Number(formData['Долг'] || 0) > 0 ? 'text-red-500' : 'text-green-500'}`}>Долг</p>
                                <p className={`text-base font-bold leading-tight ${Number(formData['Долг'] || 0) > 0 ? 'text-red-700 dark:text-red-300' : 'text-green-700 dark:text-green-300'}`}>
                                    {new Intl.NumberFormat('ru-RU', { style: 'currency', currency: 'RUB', maximumFractionDigits: 0 }).format(Number(formData['Долг'] || 0))}
                                </p>
                            </div>
                            {/* Card 2: Ending Date */}
                            <div className="p-3 rounded-lg bg-blue-50 border border-blue-100 dark:bg-blue-900/10 dark:border-blue-800">
                                <p className="text-xs font-bold uppercase text-blue-500">Окончание</p>
                                <p className="text-base font-bold leading-tight text-blue-700 dark:text-blue-300">{formatDateForDisplay(formData['Окончание'])}</p>
                            </div>
                            {/* Card 3: Warehouse */}
                            <div className="p-3 rounded-lg bg-gray-50 border border-gray-200 dark:bg-gray-800 dark:border-gray-700">
                                <p className="text-xs font-bold uppercase text-gray-500">Склад / Ячейка</p>
                                <p className="text-base font-bold leading-tight text-gray-800 dark:text-gray-200">{formData['Склад хранения']} <span className="text-gray-400">/</span> {formData['Ячейка'] || '—'}</p>
                            </div>
                            {/* Card 4: Contract (Moved here) */}
                            <div className="p-3 rounded-lg bg-gray-50 border border-gray-200 dark:bg-gray-800 dark:border-gray-700">
                                <p className="text-xs font-bold uppercase text-gray-500">Договор №</p>
                                <p className="text-base font-bold leading-tight text-gray-800 dark:text-gray-200 font-mono">{formData['Договор']}</p>
                            </div>
                        </div>

                        <SectionBlock title="Шины и Хранение" icon={<TireIcon/>}>
                             <DetailItem label="Бренд" value={formData['Бренд_Модель']} className="col-span-2" />
                             <DetailItem label="Размер шин" value={formData['Размер шин']} className="col-span-2" />

                             <TireGroupsView client={client} />

                             <DetailItem label="Сезон" value={formData['Сезон']} />
                             <DetailItem label="Кол-во" value={`${formData['Кол-во шин']} шт.`} />
                             <DetailItem label="Наличие дисков" value={formData['Наличие дисков']} />
                             <DetailItem label="DOT-код" value={formData['DOT-код']} />
                        </SectionBlock>

                        {/* Note Block (Moved Up) */}
                         <div className="bg-yellow-50 dark:bg-yellow-900/10 border border-yellow-200 dark:border-yellow-800/30 rounded-lg p-4">
                            <h4 className="text-xs font-bold text-yellow-600 dark:text-yellow-500 uppercase mb-2">Описание / Заметки</h4>
                            <p className="text-sm text-gray-800 dark:text-gray-200 font-mono whitespace-pre-wrap">{descClean || 'Нет описания'}</p>
                        </div>

                        <SectionBlock title="Финансы" icon={<CashIcon/>}>
                             <DetailItem label="Общая сумма" value={new Intl.NumberFormat('ru-RU', { style: 'currency', currency: 'RUB' }).format(Number(formData['Общая сумма'] || 0))} className="col-span-2 sm:col-span-1" />
                             <DetailItem label="Цена за месяц" value={new Intl.NumberFormat('ru-RU', { style: 'currency', currency: 'RUB' }).format(Number(formData['Цена за месяц'] || 0))} />
                             <DetailItem label="Срок хранения" value={`${formData['Срок']} мес.`} />
                             <DetailItem label="Начало хранения" value={formatDateForDisplay(formData['Начало'])} />
                             <DetailItem label="Дата напоминания" value={formatDateForDisplay(formData['Напомнить'])} />
                        </SectionBlock>

                        <SectionBlock title="Контакты" icon={<UserIcon/>}>
                            <DetailItem label="Адрес клиента" value={formData['Адрес клиента']} className="col-span-2" />
                            <DetailItem label="Chat ID" value={formData['Chat ID']} className="col-span-2" />
                        </SectionBlock>
                    </div>
                )}
                {activeTab === 'history' && <OrderHistory client={client} />}
                {activeTab === 'photos' && <PhotoGallery client={client} refreshClientData={refreshData} showToast={showToast} />}
            </div>
        )
    }

    const renderFooter = () => {
        if (mode === 'edit') {
            return (
                <>
                    <Button variant="outline" onClick={() => setMode('view')} disabled={isSubmitting}>Отмена</Button>
                    <Button onClick={handleSave} disabled={isSubmitting}>{isSubmitting ? 'Сохранение...' : 'Сохранить'}</Button>
                </>
            );
        }
        if (mode === 'message') {
            return (
                <>
                    <Button variant="outline" onClick={() => setMode('view')} disabled={isSubmitting}>Назад</Button>
                    <Button onClick={handleSendMessage} disabled={isSubmitting || (!selectedTemplateName && !preview) || !client?.['Chat ID']}>{isSubmitting ? 'Отправка...' : 'Отправить'}</Button>
                </>
            );
        }
        return (
            <div className='flex flex-wrap gap-2 w-full justify-start'>
                <Button size="sm" variant="primary" onClick={() => setMode('edit')}><EditIcon/> <span className="ml-1">Изменить</span></Button>
                <Button size="sm" variant="secondary" onClick={handleNewOrder} className="!bg-green-100 !text-green-800 hover:!bg-green-200 dark:!bg-green-800/40 dark:!text-green-200 dark:hover:!bg-green-800/60"><DocumentPlusIcon className="h-4 w-4"/> <span className="ml-1">Новый заказ</span></Button>
                <Button size="sm" variant="secondary" onClick={() => setMode('message')}><MessageIcon/> <span className="ml-1">Сообщение</span></Button>
                <Button size="sm" variant="secondary" onClick={handleGenerateReceipt} className="!bg-indigo-100 !text-indigo-800 hover:!bg-indigo-200 dark:!bg-indigo-900/40 dark:!text-indigo-200"><ReceiptIcon className="h-4 w-4"/> <span className="ml-1">Чек/Договор</span></Button>
                <div className="flex-grow"></div>
                <Button size="sm" variant="danger" onClick={handleDelete} disabled={isSubmitting}><DeleteIcon/> <span className="ml-1">Удалить</span></Button>
            </div>
        )
    }

    const modalTitleNode = (
        <div className="flex flex-col">
            <span className="text-xl font-bold leading-tight">{formData?.['Имя клиента']}</span>
            <div className="flex flex-wrap items-center gap-2 mt-1">
                 {formData?.['Номер Авто'] && (
                    <span className="inline-flex items-center px-2 py-0.5 rounded text-xs font-medium bg-gray-100 dark:bg-gray-700 text-gray-800 dark:text-gray-200 font-mono">
                        {formData['Номер Авто']}
                    </span>
                 )}
                 {formData?.['Телефон'] && (
                    <span className="text-sm text-gray-500 dark:text-gray-400">
                        {formData['Телефон']}
                    </span>
                 )}
            </div>
        </div>
    );

    return (
        <Modal 
            isOpen={isOpen}
            onClose={onClose}
            title={modalTitleNode}
            footer={<div className="flex justify-end w-full space-x-2">{renderFooter()}</div>}
        >
            <div className="border-b border-gray-200 dark:border-gray-700 mb-4">
                <nav className="-mb-px flex space-x-4" aria-label="Tabs">
                    <TabButton active={activeTab === 'details'} onClick={() => setActiveTab('details')}>Детали</TabButton>
                    <TabButton active={activeTab === 'history'} onClick={() => setActiveTab('history')}>История заказов</TabButton>
                    <TabButton active={activeTab === 'photos'} onClick={() => setActiveTab('photos')}>Фото</TabButton>
                </nav>
            </div>
            {renderContent()}
        </Modal>
    );
};

const FilterBadge: React.FC<{text: string; onRemove: () => void}> = ({ text, onRemove }) => (
  <span className="inline-flex items-center gap-x-1.5 bg-blue-100 px-2 py-1 text-xs font-medium text-blue-800 dark:bg-blue-800/30 dark:text-blue-200 rounded-full whitespace-nowrap">
    {text}
    <button
        type="button"
        onClick={onRemove}
        className="group relative -mr-0.5 h-3.5 w-3.5 rounded-full hover:bg-blue-200/60 dark:hover:bg-blue-500/30"
    >
        <span className="sr-only">Remove</span>
        <svg viewBox="0 0 14 14" className="h-3.5 w-3.5 stroke-blue-600/50 group-hover:stroke-blue-600/75 dark:stroke-blue-400/50 dark:group-hover:stroke-blue-400">
            <path d="M4 4l6 6m0-6l-6 6" />
        </svg>
    </button>
  </span>
);


export const ClientsView: React.FC<{
    clients: Client[];
    headers: string[];
    templates: MessageTemplate[];
    savedViews: SavedView[];
    onSaveViews: (views: SavedView[]) => void;
    refreshData: () => Promise<void>;
}> = ({ clients, headers, templates, savedViews, onSaveViews, refreshData }) => {
  const [searchParams, setSearchParams] = useSearchParams();
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setModalOpen] = useState(false);
  const [selectedClient, setSelectedClient] = useState<Client | null>(null);
  const [toast, setToast] = useState<{ message: string, type: 'success' | 'error' } | null>(null);
  const [filters, setFilters] = useState({
    status: 'all',
    warehouse: 'all',
    debt: searchParams.get('filter') === 'debt',
  });
  const [sortConfig, setSortConfig] = useState<{ key: string, direction: 'ascending' | 'descending' } | null>({ key: 'Начало', direction: 'descending' });
  const [isSyncing, setIsSyncing] = useState(false);
  const [newViewName, setNewViewName] = useState('');
  const [showFilters, setShowFilters] = useState(false);

  const filterOptions = useMemo(() => {
    const statuses = new Set(clients.map(c => c['Статус сделки']).filter(Boolean));
    const warehouses = new Set(clients.map(c => c['Склад хранения']).filter(Boolean));
    return {
      statuses: Array.from(statuses),
      warehouses: Array.from(warehouses),
    };
  }, [clients]);

  const sortedClients = useMemo(() => {
    let clientsToFilter = [...clients];

    if (filters.debt) {
        clientsToFilter = clientsToFilter.filter(client => (client['Долг'] || 0) > 0);
    }
    if (filters.status !== 'all') {
      clientsToFilter = clientsToFilter.filter(c => c['Статус сделки'] === filters.status);
    }
    if (filters.warehouse !== 'all') {
      clientsToFilter = clientsToFilter.filter(c => c['Склад хранения'] === filters.warehouse);
    }

    if (searchTerm) {
        clientsToFilter = clientsToFilter.filter(client =>
            Object.values(client).some(value =>
                String(value).toLowerCase().includes(searchTerm.toLowerCase())
            )
        );
    }

    if (sortConfig !== null) {
        clientsToFilter.sort((a, b) => {
            const valA = a[sortConfig.key];
            const valB = b[sortConfig.key];

            const type = getFieldType(sortConfig.key);

            let compareA = valA, compareB = valB;

            if (type === 'date') {
                compareA = valA ? new Date(valA as string).getTime() : 0;
                compareB = valB ? new Date(valB as string).getTime() : 0;
            }

            if (compareA === undefined || compareA === null) return 1;
            if (compareB === undefined || compareB === null) return -1;

            if (compareA < compareB) return sortConfig.direction === 'ascending' ? -1 : 1;
            if (compareA > compareB) return sortConfig.direction === 'ascending' ? 1 : -1;
            return 0;
        });
    }

    return clientsToFilter;
  }, [clients, searchTerm, filters, sortConfig]);

  const openModal = (client: Client) => {
    setSelectedClient(client);
    setModalOpen(true);
  };

  const closeModal = useCallback(() => {
      setModalOpen(false);
      setSelectedClient(null);
  }, []);

  useEffect(() => {
    if (selectedClient && !clients.some(c => c.id === selectedClient.id)) {
      closeModal();
    }
  }, [clients, selectedClient, closeModal]);

  useEffect(() => {
    const debtFilter = searchParams.get('filter') === 'debt';
    if(debtFilter) {
        setFilters(prev => ({...prev, debt: true}));
    }
  }, [searchParams]);

  const handleFilterChange = (type: 'status' | 'warehouse', value: string) => {
    setFilters(prev => ({ ...prev, [type]: value }));
  };

  const removeFilter = (type: keyof typeof filters) => {
    if (type === 'debt') {
      setFilters(prev => ({...prev, debt: false}));
      setSearchParams(params => {
        params.delete('filter');
        return params;
      });
    } else {
      setFilters(prev => ({ ...prev, [type]: 'all' }));
    }
  }

  const handleSortChange = (key: string) => {
      setSortConfig(prev => {
          if (prev && prev.key === key) {
              return { key, direction: prev.direction === 'ascending' ? 'descending' : 'ascending' };
          }
          const isDate = key.includes('Дата') || key.includes('Окончание') || key.includes('Начало');
          return { key, direction: isDate ? 'descending' : 'ascending' };
      });
  };

  const handleRowClick = (client: Client, e: React.MouseEvent) => {
    if ((e.target as HTMLElement).closest('a')) return;
    openModal(client);
  };

  const showToast = (message: string, type: 'success' | 'error') => {
    setToast({ message, type });
  };

  const handleSaveClient = async (clientData: Partial<Client>) => {
    try {
        if (clientData.id) {
            await api.updateClient(clientData as Client);
            showToast('Клиент успешно обновлен', 'success');
        }
        await refreshData();
    } catch (e: any) {
        showToast(e.message || 'Ошибка при сохранении клиента', 'error');
    }
  };

  const handleDeleteClient = async (clientId: string) => {
      try {
          await api.deleteClient(clientId);
          showToast('Клиент удален', 'success');
          await refreshData();
      } catch(e: any) {
          showToast(e.message || 'Ошибка при удалении клиента', 'error');
      }
  };

  const handleSendMessage = async (client: Client, messageContent: string) => {
      if (!client) return;
      const result = await api.sendMessage(client['Chat ID'] as string, messageContent);
      showToast(result.message, result.success ? 'success' : 'error');
      if (result.success) {
        await refreshData();
      }
  }

  const handleSync = async () => {
    setIsSyncing(true);
    try {
      await refreshData();
      showToast('Данные синхронизированы', 'success');
    } catch(e: any) {
      showToast(`Ошибка синхронизации: ${e.message}`, 'error');
    } finally {
      setIsSyncing(false);
    }
  }

  const handleSaveView = () => {
    if (!newViewName) {
        showToast("Введите имя для нового представления", 'error');
        return;
    }
    const newView: SavedView = {
        id: `view_${Date.now()}`,
        name: newViewName,
        filters,
        sortConfig
    };
    onSaveViews([...savedViews, newView]);
    setNewViewName('');
    showToast(`Представление "${newViewName}" сохранено`, 'success');
  };

  const handleLoadView = (viewId: string) => {
    const view = savedViews.find(v => v.id === viewId);
    if (view) {
        setFilters(view.filters);
        setSortConfig(view.sortConfig);
        showToast(`Загружено представление: ${view.name}`, 'success');
    }
  };

  const handleDeleteView = (viewId: string) => {
    onSaveViews(savedViews.filter(v => v.id !== viewId));
    showToast('Представление удалено', 'success');
  };

  const isFiltersActive = filters.status !== 'all' || filters.warehouse !== 'all' || filters.debt;


  return (
    <div className="p-4 sm:p-6 lg:p-8 space-y-6">
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}

      {/* COMPACT HEADER / FILTER BAR */}
      <Card className="!p-3 sm:!p-4">
        <div className="flex flex-col gap-3">
          {/* Top Row: Search + Actions */}
          <div className="flex gap-2 w-full">
            <div className="relative flex-grow">
               <div className="pointer-events-none absolute inset-y-0 left-0 flex items-center pl-3 text-gray-400">
                  <SearchIcon className="h-5 w-5"/>
               </div>
               <input 
                  type="text"
                  placeholder="Поиск..."
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  className="block w-full rounded-md border-gray-300 shadow-sm focus:border-primary-500 focus:ring-primary-500 py-2 pl-10 px-3 dark:bg-gray-800 dark:border-gray-600 dark:text-white placeholder:text-gray-400 dark:placeholder:text-gray-500 transition-all duration-150 h-[42px]"
               />
            </div>

            <button 
                onClick={handleSync} 
                disabled={isSyncing}
                className="flex items-center justify-center w-[42px] h-[42px] rounded-md border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-800 text-gray-600 dark:text-gray-300 hover:bg-gray-50 dark:hover:bg-gray-700 focus:ring-2 focus:ring-primary-500 transition-colors"
                title="Синхронизировать"
            >
                <SyncIcon className={`w-5 h-5 ${isSyncing ? 'animate-spin' : ''}`} />
            </button>

            <button 
                onClick={() => setShowFilters(!showFilters)}
                className={`flex items-center justify-center w-[42px] h-[42px] rounded-md border ${isFiltersActive ? 'border-primary-500 bg-primary-50 text-primary-600 dark:bg-primary-900/40 dark:text-primary-300 dark:border-primary-500' : 'border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-800 text-gray-600 dark:text-gray-300 hover:bg-gray-50 dark:hover:bg-gray-700'} focus:ring-2 focus:ring-primary-500 transition-all`}
                title="Фильтры и Сортировка"
            >
                <FilterIcon className="w-5 h-5"/>
            </button>

            <Link to="/add-client" className="flex-shrink-0">
                <Button className="h-[42px] w-[42px] sm:w-auto !p-0 sm:!px-4 flex items-center justify-center">
                    <PlusIcon />
                    <span className="hidden sm:inline ml-1">Добавить</span>
                </Button>
            </Link>
          </div>

          {/* Collapsible Filter Panel */}
          {showFilters && (
            <div className="pt-2 border-t border-gray-200 dark:border-gray-700 grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-3 animate-in slide-in-from-top-2 duration-200">
               <div>
                  <label className="block text-xs font-medium text-gray-500 dark:text-gray-400 mb-1">Сортировка</label>
                  <select value={sortConfig?.key || ''} onChange={e => handleSortChange(e.target.value)} className="block w-full rounded-md border-gray-300 shadow-sm focus:border-primary-500 focus:ring-primary-500 py-1.5 px-3 text-sm dark:bg-gray-800 dark:border-gray-600 dark:text-white">
                      <option value="Начало">По дате (новые)</option>
                      <option value="Имя клиента">По имени (А-Я)</option>
                      <option value="Окончание">По окончанию</option>
                      <option value="Долг">По долгу</option>
                  </select>
               </div>
               <div>
                  <label className="block text-xs font-medium text-gray-500 dark:text-gray-400 mb-1">Статус</label>
                  <select value={filters.status} onChange={e => handleFilterChange('status', e.target.value)} className="block w-full rounded-md border-gray-300 shadow-sm focus:border-primary-500 focus:ring-primary-500 py-1.5 px-3 text-sm dark:bg-gray-800 dark:border-gray-600 dark:text-white">
                      <option value="all">Все статусы</option>
                      {filterOptions.statuses.map(s => <option key={s} value={s}>{s}</option>)}
                  </select>
               </div>
               <div>
                   <label className="block text-xs font-medium text-gray-500 dark:text-gray-400 mb-1">Склад</label>
                   <select value={filters.warehouse} onChange={e => handleFilterChange('warehouse', e.target.value)} className="block w-full rounded-md border-gray-300 shadow-sm focus:border-primary-500 focus:ring-primary-500 py-1.5 px-3 text-sm dark:bg-gray-800 dark:border-gray-600 dark:text-white">
                      <option value="all">Все склады</option>
                      {filterOptions.warehouses.map(w => <option key={w} value={w}>{w}</option>)}
                   </select>
               </div>
               <div className="flex items-end gap-2">
                   <div className="flex-grow">
                        <label className="block text-xs font-medium text-gray-500 dark:text-gray-400 mb-1">Сохранить вид</label>
                        <input 
                            type="text" 
                            value={newViewName} 
                            onChange={(e) => setNewViewName(e.target.value)} 
                            placeholder="Название..." 
                            className="block w-full rounded-md border-gray-300 shadow-sm focus:border-primary-500 focus:ring-primary-500 py-1.5 px-3 text-sm dark:bg-gray-800 dark:border-gray-600 dark:text-white"
                        />
                   </div>
                   <Button variant="outline" onClick={handleSaveView} className="h-[34px] !px-3" title="Сохранить текущие фильтры">
                        <BookmarkIcon className="h-4 w-4"/>
                   </Button>
               </div>
            </div>
          )}

          {/* Active Filters & Saved Views Chips (Horizontal Scroll) */}
          {(isFiltersActive || savedViews.length > 0) && (
             <div className="flex items-center gap-2 overflow-x-auto pb-1 -mx-1 px-1 no-scrollbar">
                {/* Active Filter Chips */}
                {filters.debt && <FilterBadge text="С долгом" onRemove={() => removeFilter('debt')} />}
                {filters.status !== 'all' && <FilterBadge text={filters.status} onRemove={() => removeFilter('status')} />}
                {filters.warehouse !== 'all' && <FilterBadge text={filters.warehouse} onRemove={() => removeFilter('warehouse')} />}

                {isFiltersActive && savedViews.length > 0 && <div className="w-px h-4 bg-gray-300 dark:bg-gray-600 flex-shrink-0 mx-1"></div>}

                {/* Saved Views Chips */}
                {savedViews.map(view => (
                    <span key={view.id} className="inline-flex flex-shrink-0 items-center gap-x-1 bg-gray-100 pl-2.5 pr-1 py-1 text-xs font-medium text-gray-700 dark:bg-gray-700 dark:text-gray-200 rounded-full border border-gray-200 dark:border-gray-600 cursor-pointer hover:bg-gray-200 dark:hover:bg-gray-600 transition-colors">
                        <button onClick={() => handleLoadView(view.id)}>{view.name}</button>
                        <button type="button" onClick={(e) => { e.stopPropagation(); handleDeleteView(view.id); }} className="p-0.5 rounded-full hover:bg-gray-300 dark:hover:bg-gray-500 text-gray-400 hover:text-red-500">
                            <XMarkIcon className="h-3 w-3"/>
                        </button>
                    </span>
                ))}
             </div>
          )}
        </div>
      </Card>

      {/* Client List */}
      <Card className="!p-0 overflow-hidden">
        <div className="divide-y divide-gray-200 dark:divide-gray-700">
            {sortedClients.map(client => (
                <div 
                    key={client.id} 
                    onClick={(e) => handleRowClick(client, e)} 
                    className="flex items-center justify-between p-4 bg-white dark:bg-gray-800 hover:bg-gray-50 dark:hover:bg-gray-700/50 cursor-pointer transition-colors"
                >
                    <div className="flex flex-col gap-1.5 flex-1 min-w-0 pr-4">
                        <div className="flex items-center gap-2">
                             <span className="font-semibold text-gray-900 dark:text-white text-base truncate">
                                {client['Имя клиента']}
                             </span>
                             {(client['Долг'] || 0) > 0 && (
                                <span className="flex-shrink-0 w-2.5 h-2.5 rounded-full bg-red-500 shadow-sm ring-1 ring-red-400/50" title="Есть задолженность"></span>
                             )}
                        </div>
                        <div className="text-sm text-gray-500 dark:text-gray-400 flex flex-wrap items-center gap-x-2 gap-y-1">
                             <span className="font-mono bg-gray-100 dark:bg-gray-700 px-1.5 py-0.5 rounded text-xs text-gray-700 dark:text-gray-300 whitespace-nowrap">
                                {client['Номер Авто'] || 'Нет авто'}
                             </span>
                             {client['Телефон'] && (
                                <>
                                    <span className="hidden sm:inline">•</span>
                                    <span className="whitespace-nowrap">{client['Телефон']}</span>
                                </>
                             )}
                        </div>
                    </div>

                    <div className="text-right flex flex-col gap-1 flex-shrink-0">
                         <span className="text-sm text-gray-600 dark:text-gray-300">
                             {formatDateForDisplay(client['Окончание'])}
                         </span>
                         <span className={`font-bold text-sm ${
                             (client['Долг'] || 0) > 0 
                             ? 'text-red-600 dark:text-red-400' 
                             : 'text-gray-900 dark:text-white'
                         }`}>
                             {new Intl.NumberFormat('ru-RU', { style: 'currency', currency: 'RUB', maximumFractionDigits: 0 }).format(client['Долг'] || 0)}
                         </span>
                    </div>
                </div>
            ))}
        </div>
        {sortedClients.length === 0 && (
            <div className="text-center py-16 text-gray-500 dark:text-gray-400">
                <SearchIcon className="mx-auto h-12 w-12 text-gray-400" />
                <h3 className="mt-2 text-sm font-semibold text-gray-900 dark:text-white">Клиенты не найдены</h3>
                <p className="mt-1 text-sm text-gray-500">Попробуйте изменить условия поиска или фильтры.</p>
            </div>
        )}
      </Card>

      {isModalOpen && selectedClient && <ClientDetailModal
        isOpen={isModalOpen}
        onClose={closeModal}
        client={selectedClient}
        headers={headers}
        templates={templates}
        onSave={handleSaveClient}
        onDelete={handleDeleteClient}
        onSendMessage={handleSendMessage}
        refreshData={refreshData}
        showToast={showToast}
      />}
    </div>
  );
};

export const CRM_CODE = `/**
 * ==========================================
 *  ВЕРСИЯ CRM: 3.4.2 (Receipt Template)
 * ==========================================
 */

// --- КОНФИГУРАЦИЯ CRM ---
const CRM_SCRIPT_VERSION = "3.4.2";
const SHEET_NAME_CLIENTS = "WebBase";
const SHEET_NAME_TEMPLATES = "Шаблоны сообщений";
const SHEET_NAME_MASTERS = "мастера";
const SHEET_NAME_HISTORY = "History";
const SHEET_NAME_ARCHIVE = "Archive";
const SHEET_NAME_LOGS = "Logs";
const ROOT_FOLDER_NAME = "TireCRMPhotos"; 
const SCRIPT_PROPERTIES = PropertiesService.getScriptProperties();

// --- ВХОДНЫЕ ТОЧКИ ---

function doGetCRM(e) {
  return ContentService
    .createTextOutput(JSON.stringify({ status: "success", message: "CRM Service is running.", version: CRM_SCRIPT_VERSION }))
    .setMimeType(ContentService.MimeType.JSON);
}

function doPostCRM(e) {
  const lock = LockService.getScriptLock();
  // Ждем меньше, чтобы не виснуть на быстрых запросах
  lock.waitLock(10000); 

  let payload = {};

  try {
    let requestBody;

    // 1. Проверяем параметры (форма)
    if (e && e.parameter && e.parameter.payload) {
      requestBody = e.parameter.payload;
    } 
    // 2. Проверяем тело (raw JSON)
    else if (e && e.postData && e.postData.contents) {
      requestBody = e.postData.contents;
    }

    if (!requestBody) throw new Error("Empty Payload in CRM request");

    try {
        payload = JSON.parse(requestBody);
    } catch (err) {
        if (requestBody.indexOf('payload=') === 0) {
             const decoded = decodeURIComponent(requestBody.substring(8).replace(/\\+/g, ' '));
             payload = JSON.parse(decoded);
        } else {
             throw new Error("JSON Parse Error");
        }
    }

    if (payload.payload) payload = payload.payload;

    const result = routeActionCRM(payload);
    const finalResult = (result && result.status) ? result : { status: 'success', ...result };

    return ContentService.createTextOutput(JSON.stringify(finalResult)).setMimeType(ContentService.MimeType.JSON);

  } catch (error) {
    const ss = SpreadsheetApp.getActiveSpreadsheet();
    crmLogError(ss, (payload ? payload.user : "System"), (payload ? payload.action : "Unknown"), error);
    return ContentService.createTextOutput(JSON.stringify({ status: 'error', message: error.message })).setMimeType(ContentService.MimeType.JSON);
  } finally {
    lock.releaseLock();
  }
}

// --- МАРШРУТИЗАТОР CRM ---
function routeActionCRM(payload) {
  const action = payload.action;
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const user = payload.user || "System";

  switch (action) {
    case 'testconnection': return { status: 'success', message: 'Соединение ОК!', version: CRM_SCRIPT_VERSION };
    case 'getclients': return crmGetClientsAndArchive(ss);
    case 'gettemplates': return crmGetTemplatesWithDefaults(ss);
    case 'getmasters': return crmGetFullSheetData(ss, SHEET_NAME_MASTERS, 'masters');
    case 'gethistory': return crmGetHistory(ss, payload.clientId);
    case 'getarchived': return crmGetArchived(ss, payload.clientId);
    case 'getlogs': return crmGetFullSheetData(ss, SHEET_NAME_LOGS, 'logs');
    case 'getphotos': return crmGetPhotosForContract(payload.contractNumber);
    case 'add': return { status: 'success', newId: crmAddRow(ss, SHEET_NAME_CLIENTS, payload.client, user) };
    case 'update': return { status: 'success', message: crmUpdateRow(ss, SHEET_NAME_CLIENTS, payload.client, 'id', user) };
    case 'delete': return { status: 'success', message: crmDeleteRow(ss, SHEET_NAME_CLIENTS, payload.clientId, 'id') };
    case 'bulkdelete': return { status: 'success', message: crmBulkDeleteRows(ss, SHEET_NAME_CLIENTS, payload.clientIds, 'id') };
    case 'reorder': return crmReorderClient(ss, payload.oldClientId, payload.client, user);
    case 'addtemplate': return { status: 'success', message: crmAddRow(ss, SHEET_NAME_TEMPLATES, payload.template, user) };
    case 'updatetemplate': return { status: 'success', message: crmUpdateTemplate(ss, payload.template) };
    case 'deletetemplate': return { status: 'success', message: crmDeleteTemplate(ss, payload.templateName) };
    case 'addmaster': return { status: 'success', message: crmAddRow(ss, SHEET_NAME_MASTERS, payload.master, user) };
    case 'updatemaster': return { status: 'success', message: crmUpdateRow(ss, SHEET_NAME_MASTERS, payload.master, 'id', user) };
    case 'deletemaster': return { status: 'success', message: crmDeleteRow(ss, SHEET_NAME_MASTERS, payload.masterId, 'id') };

    case 'sendMessage': return crmSendMessage(payload.chatId, payload.message);
    case 'bulksend': return crmBulkSendMessage(ss, payload.clientIds, payload.templateName);
    case 'uploadfile': return { status: 'success', fileUrl: crmUploadFile(payload), message: 'Файл загружен' };
    default: return { status: 'error', message: 'Unknown action: ' + action };
  }
}

// --- БИЗНЕС-ЛОГИКА ---

function crmGetClientsAndArchive(ss) {
  const clientsResult = crmGetFullSheetData(ss, SHEET_NAME_CLIENTS, 'clients');
  const archiveResult = crmGetFullSheetData(ss, SHEET_NAME_ARCHIVE, 'archive');
  return { status: 'success', headers: clientsResult.headers || [], clients: clientsResult.clients || [], archive: archiveResult.archive || [] };
}

function crmGetHistory(ss, clientId) {
  try {
    const sheet = crmGetOrCreateSheet(ss, SHEET_NAME_HISTORY);
    if (sheet.getLastRow() < 2) return { status: 'success', history: [] };
    const data = sheet.getDataRange().getValues();
    const headers = data.shift();
    const clientIdIndex = headers.indexOf('clientId');
    if (clientIdIndex === -1) return { status: 'success', history: [] };
    const history = data.filter(row => row[clientIdIndex] == clientId).map(row => {
        let obj = {}; headers.forEach((header, i) => { obj[header] = row[i]; }); return obj;
    }).sort((a,b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
    return { status: 'success', history: history };
  } catch(e) { return { status: 'error', message: e.message }; }
}

function crmGetArchived(ss, clientId) {
  const clientSheet = crmGetOrCreateSheet(ss, SHEET_NAME_CLIENTS);
  const clientRowNum = crmFindRowById(clientSheet, clientId, 'id');
  if (clientRowNum === -1) return { status: 'success', orders: [] };
  const clientHeaders = clientSheet.getRange(1, 1, 1, clientSheet.getLastColumn()).getValues()[0];
  const clientData = clientSheet.getRange(clientRowNum, 1, 1, clientHeaders.length).getValues()[0];
  const phoneIndex = clientHeaders.indexOf('Телефон');
  const clientPhone = phoneIndex > -1 ? clientData[phoneIndex] : null;
  if (!clientPhone) return { status: 'success', orders: [] }; 
  const archiveSheet = crmGetOrCreateSheet(ss, SHEET_NAME_ARCHIVE);
  if (archiveSheet.getLastRow() < 2) return { status: 'success', orders: [] };
  const data = archiveSheet.getDataRange().getValues();
  const headers = data.shift();
  const phoneIndexInArchive = headers.indexOf('Телефон');
  if (phoneIndexInArchive === -1) return { status: 'success', orders: [] };
  const orders = data.filter(row => row[phoneIndexInArchive] == clientPhone).map(row => {
      let obj = {}; headers.forEach((header, i) => { 
        let value = row[i]; if (value instanceof Date) value = Utilities.formatDate(new Date(value), ss.getSpreadsheetTimeZone(), "yyyy-MM-dd'T'HH:mm:ss.SSS'Z'"); obj[header] = value;
      }); return obj;
  }).sort((a,b) => new Date(b['Дата добавления']).getTime() - new Date(a['Дата добавления']).getTime());
  return { status: 'success', orders: orders };
}

function crmGetPhotosForContract(contractNumber) {
  if (!contractNumber) return { status: 'success', photoUrls: [] };
  try {
    const rootFolder = crmGetAppRootFolder();
    const folders = rootFolder.getFolders();
    let clientFolder = null;
    while (folders.hasNext()) { const folder = folders.next(); if (folder.getName().startsWith(contractNumber)) { clientFolder = folder; break; } }
    if (!clientFolder) return { status: 'success', photoUrls: [] };
    const photoUrls = []; const files = clientFolder.getFiles();
    while (files.hasNext()) {
      const file = files.next();
      if (file.getSharingAccess() !== DriveApp.Access.ANYONE_WITH_LINK) { try { file.setSharing(DriveApp.Access.ANYONE_WITH_LINK, DriveApp.Permission.VIEW); } catch(e) {} }
      photoUrls.push('https://drive.google.com/uc?export=view&id=' + file.getId());
    }
    return { status: 'success', photoUrls: photoUrls };
  } catch(e) { return { status: 'success', photoUrls: [] }; }
}

function crmBulkSendMessage(ss, clientIds, templateName) {
  const token = SCRIPT_PROPERTIES.getProperty('TELEGRAM_BOT_TOKEN');
  if (!token) throw new Error("Токен Telegram не настроен.");
  const templatesData = crmGetTemplatesWithDefaults(ss);
  const template = templatesData.templates.find(t => t['Название шаблона'] === templateName);
  if (!template) throw new Error('Шаблон "' + templateName + '" не найден.');
  const clientsData = crmGetFullSheetData(ss, SHEET_NAME_CLIENTS, 'clients');
  const clientsToSend = clientsData.clients.filter(c => clientIds.includes(c.id));
  clientsToSend.forEach(client => {
    if (client['Chat ID']) {
      let message = template['Содержимое (HTML)'];
      Object.keys(client).forEach(key => { message = message.replace(new RegExp('{{' + key + '}}', 'g'), client[key] || ''); });
      crmSendMessage(client['Chat ID'], message);
    }
  });
  return { status: "success", message: "Рассылка завершена."};
}

// --- ВСПОМОГАТЕЛЬНЫЕ ФУНКЦИИ ---

function crmGetFullSheetData(ss, sheetName, dataKey) {
  try {
    const sheet = crmGetOrCreateSheet(ss, sheetName);
    if (sheet.getLastRow() < 2) return { status: 'success', headers: [], [dataKey]: [] };
    const data = sheet.getDataRange().getValues();
    const headers = data.shift();
    const result = data.map(row => {
        let obj = {}; headers.forEach((header, i) => { let value = row[i]; if (value instanceof Date) value = Utilities.formatDate(new Date(value), ss.getSpreadsheetTimeZone(), "yyyy-MM-dd'T'HH:mm:ss.SSS'Z'"); obj[header] = value; }); return obj;
    });
    if (sheetName === SHEET_NAME_LOGS) result.sort((a,b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
    return { status: 'success', headers: headers, [dataKey]: result };
  } catch (e) { throw new Error('Could not get data from sheet: ' + sheetName); }
}

function crmGetOrCreateSheet(ss, sheetName) {
  let sheet = ss.getSheetByName(sheetName);
  if (sheet) return sheet;
  sheet = ss.insertSheet(sheetName);
  const defaultHeaders = {
    [SHEET_NAME_CLIENTS]: ['id', 'Дата добавления', 'Chat ID', 'Имя клиента', 'Телефон', 'Номер Авто', 'Заказ - QR', 'Бренд_Модель', 'Размер шин', 'Сезон', 'Цена за месяц', 'Кол-во шин', 'Наличие дисков', 'Начало', 'Срок', 'Напомнить', 'Окончание', 'Склад хранения', 'Ячейка', 'Общая сумма', 'Долг', 'Договор', 'Адрес клиента', 'Статус сделки', 'Источник трафика', 'Услуга: Вывоз', 'Услуга: Мойка', 'Услуга: Упаковка', 'photoUrls'],
    [SHEET_NAME_ARCHIVE]: ['id', 'Дата добавления', 'Chat ID', 'Имя клиента', 'Телефон', 'Номер Авто', 'Заказ - QR', 'Бренд_Модель', 'Размер шин', 'Сезон', 'Цена за месяц', 'Кол-во шин', 'Наличие дисков', 'Начало', 'Срок', 'Напомнить', 'Окончание', 'Склад хранения', 'Ячейка', 'Общая сумма', 'Долг', 'Договор', 'Адрес клиента', 'Статус сделки', 'Источник трафика', 'Услуга: Вывоз', 'Услуга: Мойка', 'Услуга: Упаковка', 'photoUrls', 'Дата архивации'],
    [SHEET_NAME_TEMPLATES]: ['Название шаблона', 'Содержимое (HTML)'],
    [SHEET_NAME_MASTERS]: ['id', 'Имя', 'chatId (Telegram)', 'Услуга', 'Телефон'],
    [SHEET_NAME_HISTORY]: ['id', 'clientId', 'timestamp', 'user', 'action', 'details'],
    [SHEET_NAME_LOGS]: ['timestamp', 'level', 'user', 'action', 'message', 'details']
  };
  if (defaultHeaders[sheetName]) { sheet.appendRow(defaultHeaders[sheetName]); sheet.setFrozenRows(1); sheet.getRange(1, 1, 1, defaultHeaders[sheetName].length).setFontWeight("bold"); }
  return sheet;
}

function crmFindRowById(sheet, id, idKey) {
  if (!id) return -1;
  const headers = sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0];
  const idColIndex = headers.indexOf(idKey);
  if (idColIndex === -1) return -1;
  const data = sheet.getRange(2, idColIndex + 1, sheet.getLastRow() - 1, 1).getValues();
  for (let i = 0; i < data.length; i++) { if (String(data[i][0]) === String(id)) return i + 2; }
  return -1;
}

function crmAddRow(ss, sheetName, dataObject, user) {
  const sheet = crmGetOrCreateSheet(ss, sheetName);
  const headers = sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0];
  const newRow = headers.map(header => dataObject[header] === undefined ? '' : dataObject[header]);
  sheet.appendRow(newRow);
  const action = sheetName === SHEET_NAME_CLIENTS ? 'Клиент создан' : 'Запись добавлена';
  const clientId = sheetName === SHEET_NAME_CLIENTS ? dataObject.id : null;
  const details = Object.entries(dataObject).map(([key, value]) => key + ': ' + value).join('\\n');
  crmLogHistory(ss, clientId, user, action, details);
  return dataObject.id;
}

function crmUpdateRow(ss, sheetName, dataObject, idKey, user) {
  const sheet = crmGetOrCreateSheet(ss, sheetName);
  const headers = sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0];
  const rowNum = crmFindRowById(sheet, dataObject[idKey], idKey);
  if (rowNum === -1) throw new Error('Update failed: ID not found');
  const oldDataValues = sheet.getRange(rowNum, 1, 1, headers.length).getValues()[0];
  const oldData = headers.reduce((obj, header, i) => ({...obj, [header]: oldDataValues[i]}), {});
  const newRow = headers.map(header => dataObject[header] !== undefined ? dataObject[header] : oldData[header]);
  sheet.getRange(rowNum, 1, 1, newRow.length).setValues([newRow]);
  const changes = headers.map(header => ({ header, old: oldData[header], new: dataObject[header] })).filter(({ old, new: newValue }) => newValue !== undefined && String(old) !== String(newValue)).map(({header, old, new: newValue}) => header + ": '" + old + "' -> '" + newValue + "'");
  if (changes.length > 0 && sheetName === SHEET_NAME_CLIENTS) { crmLogHistory(ss, dataObject.id, user, 'Данные обновлены', changes.join('\\n')); }
  return 'Updated';
}

function crmDeleteRow(ss, sheetName, id, idKey) {
  const sheet = crmGetOrCreateSheet(ss, sheetName);
  const rowNum = crmFindRowById(sheet, id, idKey);
  if (rowNum > -1) { sheet.deleteRow(rowNum); return 'Deleted'; }
  return 'Not found';
}

function crmBulkDeleteRows(ss, sheetName, ids, idKey) {
  const sheet = crmGetOrCreateSheet(ss, sheetName);
  const data = sheet.getDataRange().getValues();
  const idCol = data[0].indexOf(idKey);
  const rows = [];
  for (let i = data.length - 1; i >= 1; i--) if (ids.includes(String(data[i][idCol]))) rows.push(i + 1);
  rows.forEach(r => sheet.deleteRow(r));
  return rows.length + ' записей удалено.';
}

function crmReorderClient(ss, oldClientId, newClientData, user) {
  const clientSheet = crmGetOrCreateSheet(ss, SHEET_NAME_CLIENTS);
  const archiveSheet = crmGetOrCreateSheet(ss, SHEET_NAME_ARCHIVE);
  const clientRowNum = crmFindRowById(clientSheet, oldClientId, 'id');
  if (clientRowNum === -1) throw new Error('Не удалось найти клиента: ' + oldClientId);
  const clientHeaders = clientSheet.getRange(1, 1, 1, clientSheet.getLastColumn()).getValues()[0];
  const oldClientDataValues = clientSheet.getRange(clientRowNum, 1, 1, clientHeaders.length).getValues()[0];
  const archiveHeaders = archiveSheet.getRange(1, 1, 1, archiveSheet.getLastColumn()).getValues()[0];
  const newArchiveRow = archiveHeaders.map(header => {
    const idx = clientHeaders.indexOf(header); if (header === 'Дата архивации') return new Date().toISOString(); if (idx > -1) return oldClientDataValues[idx]; return '';
  });
  archiveSheet.appendRow(newArchiveRow);
  const newRowValues = clientHeaders.map((header, index) => { if (newClientData[header] !== undefined) return newClientData[header]; return oldClientDataValues[index]; });
  clientSheet.getRange(clientRowNum, 1, 1, newRowValues.length).setValues([newRowValues]);
  crmLogHistory(ss, oldClientId, user, 'Заказ архивирован', 'Перенос в архив');
  crmLogHistory(ss, newClientData.id, user, 'Новый заказ создан', 'Обновление записи');
  return { status: 'success', message: 'Заказ успешно переоформлен.', newId: newClientData.id };
}

// --- TELEGRAM И ФАЙЛЫ ---
function crmSendMessage(chatId, message) {
  const token = SCRIPT_PROPERTIES.getProperty('TELEGRAM_BOT_TOKEN');
  if (!token) throw new Error("Токен Telegram не настроен.");
  const sanitizedMessage = message.replace(/<br\\s*\\/?>/gi, '\\n').replace(/<\\/p>/gi, '\\n').replace(/<p.*?>/gi, '').replace(/&nbsp;/g, ' ').trim();
  const url = "https://api.telegram.org/bot" + token + "/sendMessage";
  UrlFetchApp.fetch(url, { method: "post", contentType: "application/json", payload: JSON.stringify({ chat_id: String(chatId), text: sanitizedMessage, parse_mode: "HTML" }), muteHttpExceptions: true });
  return { status: "success", message: "Sent" };
}

function crmGetTemplatesWithDefaults(ss) {
  const sheet = crmGetOrCreateSheet(ss, SHEET_NAME_TEMPLATES);
  const defaultTemplates = { 
    'Напоминание о задолженности': 'Здравствуйте, {{Имя клиента}}! Долг по договору №{{Договор}}: <b>{{Долг}} ₽</b>.', 
    'Напоминание об окончании хранения': 'Здравствуйте, {{Имя клиента}}! Срок хранения шин (дог. №{{Договор}}) истекает <b>{{Окончание}}</b>.',
    'Чек (Детали заказа)': '<b>📃 ДЕТАЛИ ЗАКАЗА (ДОГОВОР)</b>\\n\\n👤 <b>Клиент:</b> {{Имя клиента}}\\n🚗 <b>Авто:</b> {{Номер Авто}}\\n📞 <b>Телефон:</b> {{Телефон}}\\n\\n🔢 <b>Договор №:</b> <code>{{Договор}}</code>\\n📅 <b>Срок хранения:</b> {{Срок}} мес.\\n(с {{Начало}} по {{Окончание}})\\n\\n- - - - - - - - - - - - - -\\n{{Заказ - QR}}\\nDOT: <b>{{DOT-код}}</b>\\n- - - - - - - - - - - - - -\\n\\n💰 <b>Сумма заказа:</b> {{Общая сумма}}\\n(Тариф: {{Цена за месяц}}/мес)\\n\\n📍 <b>Склад:</b> {{Склад хранения}}\\n\\n<i>Приём и хранение осуществляется на условиях публичной оферты otelshin.ru/dogovor</i>'
  };
  const data = sheet.getDataRange().getValues();
  const existingTemplates = data.length > 1 ? data.slice(1).map(row => row[0]) : [];
  const templatesToAdd = []; for (const name in defaultTemplates) { if (!existingTemplates.includes(name)) templatesToAdd.push([name, defaultTemplates[name]]); }
  if (templatesToAdd.length > 0) sheet.getRange(sheet.getLastRow() + 1, 1, templatesToAdd.length, 2).setValues(templatesToAdd);
  return crmGetFullSheetData(ss, SHEET_NAME_TEMPLATES, 'templates');
}

function crmUpdateTemplate(ss, t) { return crmUpdateRow(ss, SHEET_NAME_TEMPLATES, t, 'Название шаблона', 'System'); }
function crmDeleteTemplate(ss, name) { return crmDeleteRow(ss, SHEET_NAME_TEMPLATES, name, 'Название шаблона'); }

function crmGetAppRootFolder() {
  let folderId = SCRIPT_PROPERTIES.getProperty('ROOT_FOLDER_ID');
  if (folderId) { try { return DriveApp.getFolderById(folderId); } catch(e) {} }
  const folders = DriveApp.getFoldersByName(ROOT_FOLDER_NAME);
  const folder = folders.hasNext() ? folders.next() : DriveApp.createFolder(ROOT_FOLDER_NAME);
  SCRIPT_PROPERTIES.setProperty('ROOT_FOLDER_ID', folder.getId());
  return folder;
}

function crmUploadFile(payload) {
  const root = crmGetAppRootFolder();
  const name = payload.client['Договор'] ? (payload.client['Договор'] + '_' + payload.client['Имя клиента']) : payload.client.id;
  const folders = root.getFoldersByName(name);
  const folder = folders.hasNext() ? folders.next() : root.createFolder(name);
  const blob = Utilities.newBlob(Utilities.base64Decode(payload.fileData), payload.mimeType, payload.filename);
  const file = folder.createFile(blob);
  file.setSharing(DriveApp.Access.ANYONE_WITH_LINK, DriveApp.Permission.VIEW);
  return 'https://drive.google.com/uc?export=view&id=' + file.getId();
}

function crmLogHistory(ss, clientId, user, action, details) {
  try { const s = crmGetOrCreateSheet(ss, SHEET_NAME_HISTORY); s.appendRow(["evt_" + new Date().getTime(), clientId || 'N/A', new Date().toISOString(), user || 'System', action, details]); } catch (e) {}
}

function crmLogError(ss, user, action, error) {
  try { const s = crmGetOrCreateSheet(ss, SHEET_NAME_LOGS); s.appendRow([new Date().toISOString(), "ERROR", user, action, error.message, error.stack]); } catch (e) { Logger.log(e); }
}
`;

export const ROUTER_CODE = `/**
 * ГЛАВНЫЙ МАРШРУТИЗАТОР (ROUTER)
 * 
 * Этот файл является входной точкой (entry point) веб-приложения.
 * Он определяет, пришел ли запрос от CRM (React app) или от Telegram (Webhook),
 * и направляет его в соответствующий файл.
 */

function doGet(e) {
  // GET запросы в основном используются для проверки доступности
  return doGetCRM(e);
}

function doPost(e) {
  // 1. Проверяем, является ли это Webhook от Telegram
  // Telegram всегда шлет JSON, в котором есть update_id
  if (e.postData && e.postData.contents) {
    try {
      const data = JSON.parse(e.postData.contents);

      // Если есть update_id - это точно Телеграм
      if (data.update_id) {
         return doBot(data); // Функция из файла Bot.gs
      }
    } catch (err) {
      // Игнорируем ошибки парсинга здесь, пусть CRM разбирается
    }
  }

  // 2. Если это не бот, значит это CRM
  return doPostCRM(e); // Функция из файла Code.gs (или основного файла CRM)
}`;

export const BOT_CODE = `/**
 * ==========================================
 *  TELEGRAM BOT LOGIC
 * ==========================================
 */

// Глобальные настройки
const ADMIN_CHAT_ID_PROP = 'ADMIN_CHAT_ID'; // Нужно сохранить ID админа в свойства скрипта, если хотим уведомления
const BOT_TOKEN_PROP = 'TELEGRAM_BOT_TOKEN';

function getBotToken() {
  return PropertiesService.getScriptProperties().getProperty(BOT_TOKEN_PROP);
}

// Входная точка бота
function doBot(data) {
  const token = getBotToken();
  if (!token) {
    return ContentService.createTextOutput("Token not set");
  }

  try {
    // 1. ЗАЩИТА ОТ ДУБЛЕЙ (SPAM PROTECTION)
    // Telegram шлет повторы, если скрипт не ответил 200 OK быстро.
    // Мы запоминаем update_id в кэше и игнорируем повторы.
    if (data.update_id) {
       const cache = CacheService.getScriptCache();
       const processedKey = 'processed_' + data.update_id;
       if (cache.get(processedKey)) {
         // Уже обрабатывали этот апдейт, выходим
         return ContentService.createTextOutput("OK");
       }
       cache.put(processedKey, 'true', 600); // Помечаем как обработанный на 10 минут
    }

    if (data.message) {
      handleMessage(data.message);
    } else if (data.callback_query) {
      handleCallback(data.callback_query);
    }
  } catch (e) {
    // Логируем ошибку, но возвращаем 200 OK для Телеграма, чтобы он не слал повторы
    Logger.log("BOT ERROR: " + e.message);
  }

  return ContentService.createTextOutput("OK");
}

// --- КЛАВИАТУРЫ ---

function getMainMenu() {
  return {
    inline_keyboard: [
      [{text: "📝 Записаться на хранение", callback_data: "flow_signup"}],
      [{text: "👤 Личный кабинет", callback_data: "flow_lk"}],
      [{text: "💰 Цены", callback_data: "info_prices"}, {text: "ℹ️ Почему мы", callback_data: "info_why"}],
      [{text: "🔧 Шиномонтаж", callback_data: "info_fitting"}, {text: "📞 Менеджер", callback_data: "contact_manager"}]
    ]
  };
}

function getLkMenu(client) {
  return {
    inline_keyboard: [
      [{text: "📅 Продлить хранение", callback_data: "lk_extend"}],
      [{text: "🚗 Забрать шины", callback_data: "lk_pickup"}],
      [{text: "⬅️ В меню", callback_data: "main_menu"}]
    ]
  };
}

function getExtensionMenu(months, hasRims) {
  // months = 1..12
  // hasRims = boolean
  const check = hasRims ? "✅" : "⬜";
  const rows = [];

  // Кнопки выбора месяцев (1, 6, 12 или ручной ввод - упростим до популярных)
  rows.push([
    {text: (months===1?"✅ ":"")+"1 мес", callback_data: "ext_set_m_1"},
    {text: (months===6?"✅ ":"")+"6 мес", callback_data: "ext_set_m_6"},
    {text: (months===12?"✅ ":"")+"12 мес", callback_data: "ext_set_m_12"}
  ]);

  // Тоггл дисков
  rows.push([{text: check + " Хранение с дисками (+100₽)", callback_data: "ext_toggle_rims"}]);

  // Кнопка расчета/оплаты
  rows.push([{text: "🧮 Рассчитать и оплатить", callback_data: "ext_calc"}]);
  rows.push([{text: "⬅️ Назад", callback_data: "flow_lk"}]);

  return { inline_keyboard: rows };
}

// --- ОБРАБОТЧИКИ СООБЩЕНИЙ ---

function handleMessage(msg) {
  // 2. ИГНОРИРОВАНИЕ БОТОВ И СЕРВИСНЫХ СООБЩЕНИЙ
  if (!msg || !msg.chat) return;
  if (msg.from && msg.from.is_bot) return; // Не разговариваем с ботами (и с собой)

  const chatId = msg.chat.id;
  const text = msg.text;

  // Если прислали не текст (стикер, фото), а мы ждем текст - игнорируем или шлем меню
  if (!text) {
     // Можно молча выйти, чтобы не спамить "я не понял" на каждый стикер
     return; 
  }

  // Проверяем состояние пользователя (для пошаговых форм)
  const state = getUserState(chatId);

  if (text === '/start') {
    clearUserState(chatId);
    sendText(chatId, "👋 Добро пожаловать в сервис хранения шин! Выберите действие:", getMainMenu());
    return;
  }

  // Обработка шагов записи
  if (state && state.startsWith('signup_')) {
    handleSignupStep(chatId, text, state);
    return;
  }

  // Обработка выбора даты для вывоза
  if (state === 'lk_pickup_date') {
    handlePickupDate(chatId, text);
    return;
  }

  // Дефолтный ответ (только если это приватный чат, чтобы не спамить в группах)
  if (msg.chat.type === 'private') {
    sendText(chatId, "Я вас не понял. Нажмите /start для меню.");
  }
}

// --- ОБРАБОТЧИКИ КНОПОК ---

function handleCallback(cb) {
  const chatId = cb.message.chat.id;
  const messageId = cb.message.message_id;
  const data = cb.data;

  // 1. Навигация
  if (data === 'main_menu') {
    clearUserState(chatId);
    editMessage(chatId, messageId, "Главное меню:", getMainMenu());
    return;
  }

  // 2. Инфо разделы
  if (data === 'info_prices') {
    const text = "💰 **Наши цены:**\\n\\nR13-R15: 500₽/мес\\nR16-R19: 600₽/мес\\nR20+: 700₽/мес\\n\\nС дисками: +100₽/мес за комплект.";
    editMessage(chatId, messageId, text, {inline_keyboard: [[{text: "⬅️ Назад", callback_data: "main_menu"}]]});
    return;
  }

  if (data === 'info_why') {
    const text = "🏆 **Почему мы?**\\n\\n✅ Теплый склад\\n✅ Страховка шин\\n✅ Мойка и упаковка\\n✅ Доставка";
    editMessage(chatId, messageId, text, {inline_keyboard: [[{text: "⬅️ Назад", callback_data: "main_menu"}]]});
    return;
  }

  if (data === 'info_fitting') {
     const text = "🔧 **Шиномонтаж**\\n\\nМы работаем с партнерами по всему городу. Также доступен выездной шиномонтаж.\\nНажмите кнопку ниже, чтобы связаться с менеджером для записи.";
     editMessage(chatId, messageId, text, {inline_keyboard: [[{text: "📞 Записаться через менеджера", callback_data: "contact_manager"}, {text: "⬅️ Назад", callback_data: "main_menu"}]]});
     return;
  }

  if (data === 'contact_manager') {
    sendText(chatId, "Менеджер скоро свяжется с вами! (тут ссылка на контакт: @ManagerLink)");
    return;
  }

  // 3. Запись на хранение (Flow)
  if (data === 'flow_signup') {
    setUserState(chatId, 'signup_phone');
    editMessage(chatId, messageId, "✍️ **Запись на хранение**\\n\\nШаг 1/3. Введите ваш номер телефона (+7...):");
    return;
  }

  // 4. Личный кабинет
  if (data === 'flow_lk') {
    const client = findClientByChatId(chatId);
    if (client) {
      const text = \`👤 **Личный кабинет**\\n\\nКлиент: \${client['Имя клиента']}\\nАвто: \${client['Номер Авто']}\\nДоговор: \${client['Договор']}\\nШины: \${client['Заказ - QR'] || 'Не указано'}\\nСрок до: \${formatDate(client['Окончание'])}\`;
      editMessage(chatId, messageId, text, getLkMenu(client));
    } else {
      editMessage(chatId, messageId, "❌ Клиент с таким Chat ID не найден в базе.\\n\\nЕсли вы уже наш клиент, попросите менеджера привязать ваш Telegram (ID: " + chatId + ").", {inline_keyboard: [[{text: "⬅️ В меню", callback_data: "main_menu"}]]});
    }
    return;
  }

  // 5. Продление (Extension)
  if (data === 'lk_extend') {
    // Инициализируем стейт продления (по умолчанию 1 мес, без дисков)
    const extState = { months: 1, hasRims: false };
    setTempState(chatId, 'ext_data', extState);
    editMessage(chatId, messageId, "📅 **Продление хранения**\\n\\nВыберите срок и опции:", getExtensionMenu(1, false));
    return;
  }

  if (data.startsWith('ext_set_m_')) {
    const months = parseInt(data.split('_')[3]);
    const extState = getTempState(chatId, 'ext_data') || { months: 1, hasRims: false };
    extState.months = months;
    setTempState(chatId, 'ext_data', extState);
    editMessage(chatId, messageId, "📅 **Продление хранения**\\n\\nСрок изменен.", getExtensionMenu(months, extState.hasRims));
    return;
  }

  if (data === 'ext_toggle_rims') {
    const extState = getTempState(chatId, 'ext_data') || { months: 1, hasRims: false };
    extState.hasRims = !extState.hasRims;
    setTempState(chatId, 'ext_data', extState);
    editMessage(chatId, messageId, "📅 **Продление хранения**\\n\\nОпции изменены.", getExtensionMenu(extState.months, extState.hasRims));
    return;
  }

  if (data === 'ext_calc') {
    const client = findClientByChatId(chatId);
    if (!client) return;
    const extState = getTempState(chatId, 'ext_data');

    // Простая логика цены (берем цену за месяц из карточки клиента или дефолт 500)
    let basePrice = client['Цена за месяц'] || 2000; // за комплект
    // Если цена в базе указана за комплект за месяц
    // Если есть диски, накидываем 100р/мес (или 400р за комплект, зависит от бизнес логики). 
    // Предположим +400р к месячной цене комплекта.
    if (extState.hasRims) basePrice += 400;

    const total = basePrice * extState.months;

    const text = \`💵 **К оплате**\\n\\nСрок: \${extState.months} мес.\\nДиски: \${extState.hasRims ? 'Да' : 'Нет'}\\n\\n**Итого: \${total} ₽**\\n\\nПереведите по номеру +79990000000 (Сбер) и пришлите чек менеджеру.\`;
    editMessage(chatId, messageId, text, {inline_keyboard: [[{text: "⬅️ В ЛК", callback_data: "flow_lk"}]]});
    return;
  }

  // 6. Забрать шины (Pickup)
  if (data === 'lk_pickup') {
     setUserState(chatId, 'lk_pickup_date');
     editMessage(chatId, messageId, "🚗 **Забрать шины**\\n\\nНапишите желаемую дату и время (например: Завтра в 14:00):", {inline_keyboard: [[{text: "⬅️ Отмена", callback_data: "flow_lk"}]]});
     return;
  }

  // Подтверждаем колбэк чтобы колесико не крутилось
  answerCallback(cb.id);
}

// --- ЛОГИКА ШАГОВ (SIGNUP) ---

function handleSignupStep(chatId, text, state) {
  if (state === 'signup_phone') {
    setTempState(chatId, 'signup_phone', text);
    setUserState(chatId, 'signup_car');
    sendText(chatId, "✅ Принято.\\nШаг 2/3. Введите номер авто (или отправьте - если нет):");
  } else if (state === 'signup_car') {
    setTempState(chatId, 'signup_car', text);
    setUserState(chatId, 'signup_district');
    sendText(chatId, "✅ Принято.\\nШаг 3/3. Укажите ваш район (для логистики):");
  } else if (state === 'signup_district') {
    const phone = getTempState(chatId, 'signup_phone');
    const car = getTempState(chatId, 'signup_car');
    const district = text;

    // Отправка заявки менеджеру
    const adminChatId = PropertiesService.getScriptProperties().getProperty('ADMIN_CHAT_ID') || chatId; // Шлем самому себе если админ не настроен

    const report = \`🔥 **Новая заявка (Бот)**\\n\\nТел: \${phone}\\nАвто: \${car}\\nРайон: \${district}\\nChatID: \${chatId}\`;
    sendText(adminChatId, report);

    clearUserState(chatId);
    sendText(chatId, "✅ **Заявка отправлена!**\\nМенеджер свяжется с вами в ближайшее время.", getMainMenu());
  }
}

function handlePickupDate(chatId, text) {
   const client = findClientByChatId(chatId);
   const clientName = client ? client['Имя клиента'] : 'Неизвестный';

   const adminChatId = PropertiesService.getScriptProperties().getProperty('ADMIN_CHAT_ID') || chatId;
   const report = \`📤 **Заявка на выдачу**\\n\\nКлиент: \${clientName}\\nКогда: \${text}\\nChatID: \${chatId}\`;

   sendText(adminChatId, report);
   clearUserState(chatId);
   sendText(chatId, "✅ Заявка на выдачу принята. Ждите подтверждения.", getLkMenu(client));
}

// --- БД И УТИЛИТЫ ---

function findClientByChatId(chatId) {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const sheet = ss.getSheetByName("WebBase");
  const data = sheet.getDataRange().getValues();
  const headers = data[0];
  const chatCol = headers.indexOf("Chat ID");

  // Ищем с конца, чтобы найти самый свежий заказ
  for (let i = data.length - 1; i >= 1; i--) {
    if (String(data[i][chatCol]) == String(chatId)) {
      const client = {};
      headers.forEach((h, idx) => client[h] = data[i][idx]);
      return client;
    }
  }
  return null;
}

// State Management via CacheService (храним 10 минут)
function getUserState(chatId) {
  return CacheService.getScriptCache().get('state_' + chatId);
}
function setUserState(chatId, state) {
  CacheService.getScriptCache().put('state_' + chatId, state, 600);
}
function clearUserState(chatId) {
  CacheService.getScriptCache().remove('state_' + chatId);
}

// Temp Data via Cache (храним JSON string)
function setTempState(chatId, key, val) {
  // Используем префикс, чтобы не путать с userState
  const fullKey = 'data_' + chatId + '_' + key;
  const valStr = (typeof val === 'object') ? JSON.stringify(val) : String(val);
  CacheService.getScriptCache().put(fullKey, valStr, 600);
}
function getTempState(chatId, key) {
  const fullKey = 'data_' + chatId + '_' + key;
  const valStr = CacheService.getScriptCache().get(fullKey);
  if (!valStr) return null;
  try { return JSON.parse(valStr); } catch(e) { return valStr; }
}

// --- TELEGRAM API WRAPPERS ---

function sendText(chatId, text, keyboard) {
  const token = getBotToken();
  const payload = {
    chat_id: String(chatId),
    text: text,
    parse_mode: 'Markdown'
  };
  if (keyboard) payload.reply_markup = keyboard;

  UrlFetchApp.fetch("https://api.telegram.org/bot" + token + "/sendMessage", {
    method: 'post',
    contentType: 'application/json',
    payload: JSON.stringify(payload)
  });
}

function editMessage(chatId, messageId, text, keyboard) {
  const token = getBotToken();
  const payload = {
    chat_id: String(chatId),
    message_id: messageId,
    text: text,
    parse_mode: 'Markdown'
  };
  if (keyboard) payload.reply_markup = keyboard;

  try {
    UrlFetchApp.fetch("https://api.telegram.org/bot" + token + "/editMessageText", {
      method: 'post',
      contentType: 'application/json',
      payload: JSON.stringify(payload)
    });
  } catch (e) {
    // Иногда редактирование падает если текст не изменился, это норм
  }
}

function answerCallback(callbackQueryId) {
   const token = getBotToken();
   UrlFetchApp.fetch("https://api.telegram.org/bot" + token + "/answerCallbackQuery", {
    method: 'post',
    contentType: 'application/json',
    payload: JSON.stringify({ callback_query_id: callbackQueryId })
  });
}

function formatDate(dateStr) {
  if (!dateStr) return "-";
  try {
    const d = new Date(dateStr);
    return d.toLocaleDateString("ru-RU");
  } catch (e) { return dateStr; }
}`;

