export const Modal: React.FC<ModalProps> = ({ isOpen, onClose, title, children, footer }) => {
  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center" aria-labelledby="modal-title" role="dialog" aria-modal="true">
      {/* Backdrop - Visible only on Desktop to focus attention */}
      <div className="absolute inset-0 bg-black/60 backdrop-blur-sm transition-opacity hidden sm:block" onClick={onClose}></div>

      {/* 
         Modal Container:
         - Mobile: Fixed inset-0 (Full Screen), white bg, no rounding. Looks like a native page.
         - Desktop: Centered, rounded, shadow, max-width constrained.
      */}
      <div className="relative w-full h-full sm:h-auto sm:max-h-[90vh] sm:max-w-2xl bg-white dark:bg-gray-900 sm:rounded-xl shadow-2xl flex flex-col overflow-hidden animate-in slide-in-from-bottom-5 sm:zoom-in-95 duration-200">

