            {title}
          </div>

          {/* Close Button */}
          <button
            type="button"
            className="absolute right-3 top-3 text-gray-400 bg-gray-100 dark:bg-gray-800 hover:bg-gray-200 hover:text-gray-900 dark:hover:bg-gray-700 dark:hover:text-white rounded-full p-2 inline-flex items-center transition-colors focus:outline-none focus:ring-2 focus:ring-primary-500"
