          >
            <span className="sr-only">Закрыть</span>
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"></path></svg>
          </button>
        </div>

        {/* Scrollable Content Area */}
        <div className="flex-1 overflow-y-auto overflow-x-hidden bg-gray-50 dark:bg-gray-950 sm:bg-white sm:dark:bg-gray-900">
           <div className="p-4 sm:p-6 space-y-4 pb-24 sm:pb-6"> 
              {/* pb-24 adds extra padding at bottom so content isn't hidden behind mobile fixed footer */}
              {children}
           </div>
        </div>

        {/* Footer - Fixed at bottom */}
        {footer && (
          <div className="px-4 py-3 sm:px-6 sm:py-4 border-t border-gray-200 dark:border-gray-800 bg-white dark:bg-gray-900 shrink-0 pb-safe sm:pb-4 z-20 shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.05)] sm:shadow-none">
            {footer}
          </div>
        )}
      </div>
    </div>
  );
};

